// O(1) - Constant: same speed no matter what
public int getFirst(int[] arr) {
    return arr[0];  // Always 1 operation, even for 1 million items
}

// O(n) - Linear: grows with input size
public int findMax(int[] arr) {
    int max = arr[0];
    for (int num : arr) {  // Touch every element once
        if (num > max) max = num;
    }
    return max;
}

// O(log n) - Logarithmic: cuts problem in half each time
public int binarySearch(int[] arr, int target) {
    int left = 0, right = arr.length - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;  // Halve the search space
        if (arr[mid] == target) return mid;
        if (arr[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}

// O(n²) - Quadratic: nested loops = trouble for large inputs
public void bubbleSort(int[] arr) {
    for (int i = 0; i < arr.length; i++) {       // n times
        for (int j = 0; j < arr.length - 1; j++) { // n times each
            // Total: n * n = n² operations!
            if (arr[j] > arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

// O(1) Space - Just a few variables, no matter how big the input
public void reverseArray(int[] arr) {
    int left = 0, right = arr.length - 1;  // Only 3 variables!
    while (left < right) {
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
}

// O(n) Space - Creating a copy needs space proportional to input
public int[] copyArray(int[] arr) {
    int[] copy = new int[arr.length];  // New array = O(n) space
    for (int i = 0; i < arr.length; i++) {
        copy[i] = arr[i];
    }
    return copy;
}

// O(n) Space - Recursion uses stack memory!
public int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);  // Each call adds to the stack
    // factorial(5) → factorial(4) → ... → factorial(1)
    // That's 5 function calls sitting in memory at once!
}

