// Reverse array in-place — the classic two-pointer swap
public void reverse(int[] arr) {
    int left = 0, right = arr.length - 1;
    while (left < right) {
        // Swap the cars at left and right spots
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;    // Move toward center
        right--;   // Move toward center
    }
}

// Two Sum on SORTED array — the classic two-pointer example
public int[] twoSum(int[] arr, int target) {
    int left = 0, right = arr.length - 1;

    while (left < right) {
        int sum = arr[left] + arr[right];

        if (sum == target) {
            return new int[]{left, right};  // Found it!
        } else if (sum < target) {
            left++;   // Need bigger sum → move left pointer right
        } else {
            right--;  // Need smaller sum → move right pointer left
        }
    }
    return new int[]{-1, -1};  // No pair found
}

// Remove Duplicates from Sorted Array
// Key insight: slow pointer marks where to put next unique
public int removeDuplicates(int[] arr) {
    if (arr.length == 0) return 0;

    int slow = 0;  // Points to last unique element

    for (int fast = 1; fast < arr.length; fast++) {
        if (arr[fast] != arr[slow]) {  // Found new unique!
            slow++;                     // Make room
            arr[slow] = arr[fast];      // Place it
        }
    }
    return slow + 1;  // Count of unique elements
}

// Maximum Sum Subarray of Size K — the classic fixed window
public int maxSumSubarray(int[] arr, int k) {
    // First, calculate sum of first window
    int windowSum = 0;
    for (int i = 0; i < k; i++) {
        windowSum += arr[i];
    }
    int maxSum = windowSum;

    // Now slide: remove leftmost, add rightmost
    for (int i = k; i < arr.length; i++) {
        windowSum += arr[i] - arr[i - k];  // Slide!
        maxSum = Math.max(maxSum, windowSum);
    }
    return maxSum;
}

// Longest Substring Without Repeating Characters — variable window
public int lengthOfLongestSubstring(String s) {
    Set<Character> seen = new HashSet<>();
    int maxLen = 0, left = 0;

    for (int right = 0; right < s.length(); right++) {
        // Shrink window until no duplicate
        while (seen.contains(s.charAt(right))) {
            seen.remove(s.charAt(left));
            left++;  // Shrink from left
        }

        seen.add(s.charAt(right));  // Expand window
        maxLen = Math.max(maxLen, right - left + 1);
    }
    return maxLen;
}

// Maximum Subarray Sum - O(n)
public int maxSubArray(int[] nums) {
    int maxSum = nums[0];
    int currentSum = nums[0];

    for (int i = 1; i < nums.length; i++) {
        currentSum = Math.max(nums[i], currentSum + nums[i]);
        maxSum = Math.max(maxSum, currentSum);
    }
    return maxSum;
}

// Return subarray indices
public int[] maxSubArrayWithIndices(int[] nums) {
    int maxSum = nums[0], currentSum = nums[0];
    int start = 0, end = 0, tempStart = 0;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] > currentSum + nums[i]) {
            currentSum = nums[i];
            tempStart = i;
        } else {
            currentSum = currentSum + nums[i];
        }

        if (currentSum > maxSum) {
            maxSum = currentSum;
            start = tempStart;
            end = i;
        }
    }
    return new int[]{start, end, maxSum};
}

// Maximum Product Subarray - O(n)
public int maxProduct(int[] nums) {
    int maxProd = nums[0];
    int maxEndingHere = nums[0];
    int minEndingHere = nums[0];

    for (int i = 1; i < nums.length; i++) {
        int temp = maxEndingHere;
        maxEndingHere = Math.max(nums[i], 
            Math.max(maxEndingHere * nums[i], minEndingHere * nums[i]));
        minEndingHere = Math.min(nums[i], 
            Math.min(temp * nums[i], minEndingHere * nums[i]));
        maxProd = Math.max(maxProd, maxEndingHere);
    }
    return maxProd;
}

// Sort Colors (0s, 1s, 2s) - O(n) time, O(1) space
public void sortColors(int[] nums) {
    int low = 0, mid = 0, high = nums.length - 1;

    while (mid <= high) {
        if (nums[mid] == 0) {
            swap(nums, low, mid);
            low++;
            mid++;
        } else if (nums[mid] == 1) {
            mid++;
        } else { // nums[mid] == 2
            swap(nums, mid, high);
            high--;
        }
    }
}

private void swap(int[] arr, int i, int j) {
    int temp = arr[i];
    arr[i] = arr[j];
    arr[j] = temp;
}

// Segregate 0s and 1s
public void segregate01(int[] arr) {
    int left = 0, right = arr.length - 1;
    while (left < right) {
        while (left < right && arr[left] == 0) left++;
        while (left < right && arr[right] == 1) right--;
        if (left < right) {
            swap(arr, left, right);
            left++;
            right--;
        }
    }
}

// Rotate Array by k positions - O(n) time, O(1) space
public void rotate(int[] arr, int k) {
    k = k % arr.length;
    reverse(arr, 0, arr.length - 1);
    reverse(arr, 0, k - 1);
    reverse(arr, k, arr.length - 1);
}

private void reverse(int[] arr, int start, int end) {
    while (start < end) {
        int temp = arr[start];
        arr[start] = arr[end];
        arr[end] = temp;
        start++;
        end--;
    }
}

// Find Missing Number (1 to n) - O(n)
public int findMissing(int[] arr) {
    int n = arr.length + 1;
    int expectedSum = n * (n + 1) / 2;
    int actualSum = 0;
    for (int num : arr) {
        actualSum += num;
    }
    return expectedSum - actualSum;
}

// Find Duplicate Number - O(n) time, O(1) space
public int findDuplicate(int[] nums) {
    int slow = nums[0];
    int fast = nums[0];

    do {
        slow = nums[slow];
        fast = nums[nums[fast]];
    } while (slow != fast);

    slow = nums[0];
    while (slow != fast) {
        slow = nums[slow];
        fast = nums[fast];
    }
    return slow;
}

// Merge Two Sorted Arrays - O(m + n)
public int[] merge(int[] arr1, int[] arr2) {
    int[] result = new int[arr1.length + arr2.length];
    int i = 0, j = 0, k = 0;

    while (i < arr1.length && j < arr2.length) {
        if (arr1[i] <= arr2[j]) {
            result[k++] = arr1[i++];
        } else {
            result[k++] = arr2[j++];
        }
    }

    while (i < arr1.length) result[k++] = arr1[i++];
    while (j < arr2.length) result[k++] = arr2[j++];

    return result;
}

