// Simple Palindrome - O(n)
public boolean isPalindrome(String s) {
    int left = 0, right = s.length() - 1;
    while (left < right) {
        if (s.charAt(left) != s.charAt(right)) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

// Valid Palindrome (Alphanumeric only) - O(n)
public boolean isValidPalindrome(String s) {
    int left = 0, right = s.length() - 1;

    while (left < right) {
        while (left < right && !Character.isLetterOrDigit(s.charAt(left))) {
            left++;
        }
        while (left < right && !Character.isLetterOrDigit(s.charAt(right))) {
            right--;
        }

        if (Character.toLowerCase(s.charAt(left)) != 
            Character.toLowerCase(s.charAt(right))) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

// Longest Palindromic Substring - O(n²)
public String longestPalindrome(String s) {
    if (s == null || s.length() < 1) return "";
    int start = 0, end = 0;

    for (int i = 0; i < s.length(); i++) {
        int len1 = expandAroundCenter(s, i, i);     // Odd length
        int len2 = expandAroundCenter(s, i, i + 1); // Even length
        int len = Math.max(len1, len2);

        if (len > end - start) {
            start = i - (len - 1) / 2;
            end = i + len / 2;
        }
    }
    return s.substring(start, end + 1);
}

private int expandAroundCenter(String s, int left, int right) {
    while (left >= 0 && right < s.length() && 
           s.charAt(left) == s.charAt(right)) {
        left--;
        right++;
    }
    return right - left - 1;
}

// Using Sorting - O(n log n)
public boolean isAnagramSort(String s1, String s2) {
    if (s1.length() != s2.length()) return false;

    char[] arr1 = s1.toCharArray();
    char[] arr2 = s2.toCharArray();
    Arrays.sort(arr1);
    Arrays.sort(arr2);

    return Arrays.equals(arr1, arr2);
}

// Using Frequency Array - O(n) time, O(1) space
public boolean isAnagram(String s1, String s2) {
    if (s1.length() != s2.length()) return false;

    int[] count = new int[26];
    for (int i = 0; i < s1.length(); i++) {
        count[s1.charAt(i) - 'a']++;
        count[s2.charAt(i) - 'a']--;
    }

    for (int c : count) {
        if (c != 0) return false;
    }
    return true;
}

// Group Anagrams - O(n * k log k)
public List<List<String>> groupAnagrams(String[] strs) {
    Map<String, List<String>> map = new HashMap<>();

    for (String s : strs) {
        char[] chars = s.toCharArray();
        Arrays.sort(chars);
        String key = new String(chars);

        map.putIfAbsent(key, new ArrayList<>());
        map.get(key).add(s);
    }

    return new ArrayList<>(map.values());
}

// Group Anagrams Optimized - O(n * k)
public List<List<String>> groupAnagramsOptimized(String[] strs) {
    Map<String, List<String>> map = new HashMap<>();

    for (String s : strs) {
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }

        StringBuilder key = new StringBuilder();
        for (int i = 0; i < 26; i++) {
            key.append('#').append(count[i]);
        }

        String keyStr = key.toString();
        map.putIfAbsent(keyStr, new ArrayList<>());
        map.get(keyStr).add(s);
    }

    return new ArrayList<>(map.values());
}

// Reverse String - O(n)
public String reverse(String s) {
    char[] chars = s.toCharArray();
    int left = 0, right = chars.length - 1;
    while (left < right) {
        char temp = chars[left];
        chars[left] = chars[right];
        chars[right] = temp;
        left++;
        right--;
    }
    return new String(chars);
}

// Reverse Words in String - O(n)
public String reverseWords(String s) {
    String[] words = s.trim().split("\\s+");
    StringBuilder result = new StringBuilder();

    for (int i = words.length - 1; i >= 0; i--) {
        result.append(words[i]);
        if (i > 0) result.append(" ");
    }
    return result.toString();
}

// Rotate String - O(n)
public boolean isRotation(String s1, String s2) {
    if (s1.length() != s2.length()) return false;
    String doubled = s1 + s1;
    return doubled.contains(s2);
}

// Left Rotate String by d positions
public String leftRotate(String s, int d) {
    d = d % s.length();
    return s.substring(d) + s.substring(0, d);
}

// Longest Common Prefix - O(n * m)
public String longestCommonPrefix(String[] strs) {
    if (strs == null || strs.length == 0) return "";

    String prefix = strs[0];
    for (int i = 1; i < strs.length; i++) {
        while (strs[i].indexOf(prefix) != 0) {
            prefix = prefix.substring(0, prefix.length() - 1);
            if (prefix.isEmpty()) return "";
        }
    }
    return prefix;
}

// Longest Repeating Character Replacement - O(n)
public int characterReplacement(String s, int k) {
    int[] count = new int[26];
    int maxCount = 0, maxLength = 0, left = 0;

    for (int right = 0; right < s.length(); right++) {
        maxCount = Math.max(maxCount, ++count[s.charAt(right) - 'A']);

        while (right - left + 1 - maxCount > k) {
            count[s.charAt(left) - 'A']--;
            left++;
        }

        maxLength = Math.max(maxLength, right - left + 1);
    }
    return maxLength;
}

// Count and Say - O(n * length)
public String countAndSay(int n) {
    String result = "1";

    for (int i = 1; i < n; i++) {
        StringBuilder next = new StringBuilder();
        int count = 1;
        char current = result.charAt(0);

        for (int j = 1; j < result.length(); j++) {
            if (result.charAt(j) == current) {
                count++;
            } else {
                next.append(count).append(current);
                current = result.charAt(j);
                count = 1;
            }
        }
        next.append(count).append(current);
        result = next.toString();
    }
    return result;
}

// KMP Pattern Matching - O(n + m)
public int strStr(String haystack, String needle) {
    if (needle.isEmpty()) return 0;

    int[] lps = computeLPS(needle);
    int i = 0, j = 0;

    while (i < haystack.length()) {
        if (haystack.charAt(i) == needle.charAt(j)) {
            i++;
            j++;
        }

        if (j == needle.length()) {
            return i - j;
        } else if (i < haystack.length() && 
                   haystack.charAt(i) != needle.charAt(j)) {
            if (j != 0) {
                j = lps[j - 1];
            } else {
                i++;
            }
        }
    }
    return -1;
}

private int[] computeLPS(String pattern) {
    int[] lps = new int[pattern.length()];
    int len = 0, i = 1;

    while (i < pattern.length()) {
        if (pattern.charAt(i) == pattern.charAt(len)) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
    return lps;
}

// Each node holds data + pointer to next node
class Node {
    int data;
    Node next;  // The 'clue' to the next node

    Node(int data) {
        this.data = data;
        this.next = null;  // No clue yet
    }
}

public class LinkedList {
    Node head;  // Entry point to the list

    // Insert at Beginning - O(1) — just update head!
    public void insertAtBeginning(int data) {
        Node newNode = new Node(data);
        newNode.next = head;  // New node points to old head
        head = newNode;       // New node becomes head
    }

    // Insert at End - O(n) — have to walk to the end
    public void insertAtEnd(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            return;
        }

        Node current = head;
        while (current.next != null) {  // Walk to the last node
            current = current.next;
        }
        current.next = newNode;  // Link last node to new node
    }

    // Delete by Value - O(n) — find it, then rewire
    public void delete(int key) {
        if (head == null) return;

        // Special case: deleting head
        if (head.data == key) {
            head = head.next;  // Skip over old head
            return;
        }

        Node current = head;
        while (current.next != null && current.next.data != key) {
            current = current.next;  // Find the node BEFORE the one to delete
        }

        if (current.next != null) {
            current.next = current.next.next;  // Skip over deleted node
        }
    }
}

// Iterative Approach - O(n) time, O(1) space
public Node reverse() {
    Node prev = null;
    Node current = head;
    Node next = null;

    while (current != null) {
        next = current.next;  // Store next
        current.next = prev;  // Reverse link
        prev = current;       // Move prev forward
        current = next;       // Move current forward
    }
    head = prev;
    return head;
}

// Recursive Approach - O(n) time, O(n) space
public Node reverseRecursive(Node node) {
    if (node == null || node.next == null) {
        return node;
    }

    Node newHead = reverseRecursive(node.next);
    node.next.next = node;
    node.next = null;

    return newHead;
}

// Reverse in Groups of K - O(n)
public Node reverseKGroup(Node head, int k) {
    Node current = head;
    int count = 0;

    // Check if there are k nodes
    while (current != null && count < k) {
        current = current.next;
        count++;
    }

    if (count == k) {
        current = reverseKGroup(current, k);

        while (count > 0) {
            Node next = head.next;
            head.next = current;
            current = head;
            head = next;
            count--;
        }
        head = current;
    }
    return head;
}

// Detect if cycle exists — O(n) time, O(1) space!
public boolean hasCycle() {
    if (head == null) return false;

    Node slow = head;  // Tortoise: moves 1 step
    Node fast = head;  // Hare: moves 2 steps

    while (fast != null && fast.next != null) {
        slow = slow.next;       // 1 step
        fast = fast.next.next;  // 2 steps

        if (slow == fast) {
            return true;  // They met! There's a cycle.
        }
    }
    return false;  // Fast hit the end → no cycle
}

// Find WHERE the cycle starts — the clever part!
public Node detectCycleStart() {
    Node slow = head, fast = head;

    // Phase 1: Find meeting point
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) break;
    }

    // No cycle
    if (fast == null || fast.next == null) return null;

    // Phase 2: Reset slow to head, move both at same speed
    slow = head;
    while (slow != fast) {
        slow = slow.next;
        fast = fast.next;  // Both move 1 step now
    }
    return slow;  // This is where the cycle begins!
}

// Find Middle Element - O(n)
public Node findMiddle() {
    if (head == null) return null;

    Node slow = head;
    Node fast = head;

    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
    }
    return slow;
}

// Merge Two Sorted Lists - O(m + n)
public Node mergeTwoLists(Node l1, Node l2) {
    Node dummy = new Node(0);
    Node current = dummy;

    while (l1 != null && l2 != null) {
        if (l1.data <= l2.data) {
            current.next = l1;
            l1 = l1.next;
        } else {
            current.next = l2;
            l2 = l2.next;
        }
        current = current.next;
    }

    current.next = (l1 != null) ? l1 : l2;
    return dummy.next;
}

// Merge K Sorted Lists - O(N log k)
public Node mergeKLists(Node[] lists) {
    if (lists == null || lists.length == 0) return null;

    PriorityQueue<Node> pq = new PriorityQueue<>((a, b) -> a.data - b.data);

    for (Node node : lists) {
        if (node != null) {
            pq.offer(node);
        }
    }

    Node dummy = new Node(0);
    Node current = dummy;

    while (!pq.isEmpty()) {
        Node min = pq.poll();
        current.next = min;
        current = current.next;

        if (min.next != null) {
            pq.offer(min.next);
        }
    }
    return dummy.next;
}

// Check if Palindrome - O(n)
public boolean isPalindrome() {
    if (head == null || head.next == null) return true;

    // Find middle
    Node slow = head, fast = head;
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
    }

    // Reverse second half
    Node prev = null, current = slow;
    while (current != null) {
        Node next = current.next;
        current.next = prev;
        prev = current;
        current = next;
    }

    // Compare
    Node left = head, right = prev;
    while (right != null) {
        if (left.data != right.data) return false;
        left = left.next;
        right = right.next;
    }
    return true;
}

// Doubly Linked List Node
class DoublyNode {
    int data;
    DoublyNode prev;
    DoublyNode next;

    DoublyNode(int data) {
        this.data = data;
        this.prev = null;
        this.next = null;
    }
}

public class DoublyLinkedList {
    DoublyNode head;

    // Insert at Beginning - O(1)
    public void insertAtBeginning(int data) {
        DoublyNode newNode = new DoublyNode(data);
        newNode.next = head;

        if (head != null) {
            head.prev = newNode;
        }
        head = newNode;
    }

    // Insert at End - O(n)
    public void insertAtEnd(int data) {
        DoublyNode newNode = new DoublyNode(data);

        if (head == null) {
            head = newNode;
            return;
        }

        DoublyNode current = head;
        while (current.next != null) {
            current = current.next;
        }

        current.next = newNode;
        newNode.prev = current;
    }

    // Delete Node - O(1) if node reference given
    public void deleteNode(DoublyNode node) {
        if (node == null) return;

        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next;
        }

        if (node.next != null) {
            node.next.prev = node.prev;
        }
    }

    // Reverse - O(n)
    public void reverse() {
        DoublyNode current = head;
        DoublyNode temp = null;

        while (current != null) {
            temp = current.prev;
            current.prev = current.next;
            current.next = temp;
            current = current.prev;
        }

        if (temp != null) {
            head = temp.prev;
        }
    }
}

