// 🚨 EDGE CASES TO ALWAYS CHECK

// ARRAYS
if (arr == null || arr.length == 0) return ...;
if (arr.length == 1) return arr[0];  // Single element
// Watch for: off-by-one errors with length-1

// STRINGS
if (s == null || s.isEmpty()) return ...;
// Watch for: uppercase vs lowercase, spaces

// LINKED LISTS
if (head == null) return null;
if (head.next == null) return head;  // Single node
// Watch for: losing the next pointer before updating

// TREES
if (root == null) return ...;  // Empty tree
if (root.left == null && root.right == null) ...;  // Leaf
// Watch for: asymmetric trees, single-child nodes

// NUMBERS
// Overflow: use long for intermediate calculations
// Division by zero: check before dividing
// Negative numbers: affect modulo results differently

