// DATA STRUCTURE SELECTION GUIDE

// NEED O(1) LOOKUP BY KEY? → HashMap
Map<String, Integer> cache = new HashMap<>();

// NEED O(1) UNIQUE CHECK? → HashSet
Set<Integer> seen = new HashSet<>();

// NEED SORTED ORDER? → TreeMap/TreeSet (O(log n))
TreeMap<Integer, String> sorted = new TreeMap<>();

// NEED MIN/MAX QUICKLY? → Heap (PriorityQueue)
PriorityQueue<Integer> minHeap = new PriorityQueue<>();
PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Collections.reverseOrder());

// NEED FIFO ORDER? → Queue (LinkedList or ArrayDeque)
Queue<Integer> queue = new LinkedList<>();

// NEED LIFO/UNDO? → Stack (ArrayDeque)
Deque<Integer> stack = new ArrayDeque<>();

// NEED FAST INSERT/DELETE + ITERATION? → LinkedList
LinkedList<Integer> list = new LinkedList<>();

// NEED RANDOM ACCESS BY INDEX? → ArrayList
ArrayList<Integer> arr = new ArrayList<>();

// NEED BOTH ENDS? → Deque (ArrayDeque)
Deque<Integer> deque = new ArrayDeque<>();

// COMPLEXITY QUICK REFERENCE:
// ArrayList:  get O(1), add O(1)*, insert O(n)
// LinkedList: get O(n), add O(1), insert O(1)
// HashMap:    all operations O(1) average
// TreeMap:    all operations O(log n)
// PriorityQueue: add O(log n), peek O(1), poll O(log n)
